import{_ as e,o,c as a,a2 as r}from"./chunks/framework.DTa47_fH.js";const h=JSON.parse('{"title":"Parameterise the .pbit query paths -- one-time migration","description":"","frontmatter":{},"headers":[],"relativePath":"templates/PARAMETERISE-PBIT-QUERIES.md","filePath":"templates/PARAMETERISE-PBIT-QUERIES.md"}'),d={name:"templates/PARAMETERISE-PBIT-QUERIES.md"};function s(i,t,n,c,p,l){return o(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="parameterise-the-pbit-query-paths-one-time-migration" tabindex="-1">Parameterise the .pbit query paths -- one-time migration <a class="header-anchor" href="#parameterise-the-pbit-query-paths-one-time-migration" aria-label="Permalink to &quot;Parameterise the .pbit query paths -- one-time migration&quot;">​</a></h1><p>The v1.0 <code>.pbit</code> files (swao-report.pbit + swao-portfolio.pbit) were authored by per-CSV <code>Get Data &gt; Text/CSV</code> imports. PowerBI baked the absolute path into each query&#39;s M code instead of routing through the <code>SWAOExportPath</code> / <code>SWAOPortfolioExportPath</code> parameter. As a result, refreshing against a new assessment bundle requires editing 17 (single-app) or 19 (portfolio) absolute paths -- one per query.</p><p>This document is the one-time fix. After applying it, changing the parameter value in PowerBI&#39;s <code>Parameter verwalten</code> updates every query in one click.</p><p>After the fix, re-save the .pbit. The fix then ships with the template forever.</p><hr><h2 id="recipe-per-query-identical-pattern-17-or-19-times" tabindex="-1">Recipe per query (identical pattern, 17 or 19 times) <a class="header-anchor" href="#recipe-per-query-identical-pattern-17-or-19-times" aria-label="Permalink to &quot;Recipe per query (identical pattern, 17 or 19 times)&quot;">​</a></h2><p>In Power Query Editor: open each query -&gt; <code>Start &gt; Erweiterter Editor</code> -&gt; swap the <strong><code>Quelle =</code></strong> line. Leave the <code>Höher gestufte Header</code>, <code>Geänderter Typ</code>, and <code>in</code> lines untouched.</p><h3 id="generic-before-after" tabindex="-1">Generic before / after <a class="header-anchor" href="#generic-before-after" aria-label="Permalink to &quot;Generic before / after&quot;">​</a></h3><p><strong>Before</strong> (the line that needs changing):</p><div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quelle = Csv.Document(File.Contents(&quot;C:\\Projects\\accenture\\swao\\examples\\portfolio-workspace\\portfolio\\apps\\sovereign-health\\wsp\\exports\\2026-05-10T05-34-42\\star\\&lt;FILENAME&gt;.csv&quot;),[Delimiter=&quot;,&quot;, Columns=N, Encoding=65001, QuoteStyle=QuoteStyle.None]),</span></span></code></pre></div><p><strong>After</strong> (the only change is the file argument to <code>File.Contents</code>):</p><div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quelle = Csv.Document(File.Contents(SWAOExportPath &amp; &quot;\\&lt;FILENAME&gt;.csv&quot;),[Delimiter=&quot;,&quot;, Columns=N, Encoding=65001, QuoteStyle=QuoteStyle.None]),</span></span></code></pre></div><p>The exact <code>Columns=N</code> and <code>QuoteStyle=...</code> values in the existing query stay as PowerBI generated them; do not change those. The only text you replace is the quoted absolute-path string (from <code>&quot;C:\\...</code> to <code>.csv&quot;</code>) with <code>SWAOExportPath &amp; &quot;\\&lt;FILENAME&gt;.csv&quot;</code>.</p><p>For the portfolio template, the parameter is named <strong><code>SWAOPortfolioExportPath</code></strong> instead of <code>SWAOExportPath</code>.</p><hr><h2 id="worked-example-dim-app" tabindex="-1">Worked example -- dim_app <a class="header-anchor" href="#worked-example-dim-app" aria-label="Permalink to &quot;Worked example -- dim_app&quot;">​</a></h2><h3 id="before-your-current-dim-app-query" tabindex="-1">Before (your current dim_app query) <a class="header-anchor" href="#before-your-current-dim-app-query" aria-label="Permalink to &quot;Before (your current dim_app query)&quot;">​</a></h3><div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let</span></span>
<span class="line"><span>    Quelle = Csv.Document(File.Contents(&quot;C:\\Projects\\accenture\\swao\\examples\\portfolio-workspace\\portfolio\\apps\\sovereign-health\\wsp\\exports\\2026-05-10T05-34-42\\star\\dim_app.csv&quot;),[Delimiter=&quot;,&quot;, Columns=11, Encoding=65001, QuoteStyle=QuoteStyle.None]),</span></span>
<span class="line"><span>    #&quot;Höher gestufte Header&quot; = Table.PromoteHeaders(Quelle, [PromoteAllScalars=true]),</span></span>
<span class="line"><span>    #&quot;Geänderter Typ&quot; = Table.TransformColumnTypes(#&quot;Höher gestufte Header&quot;,{{&quot;app_id&quot;, type text}, {&quot;name&quot;, type text}, {&quot;business_domain&quot;, type text}, {&quot;business_criticality&quot;, type text}, {&quot;regulatory_class&quot;, type text}, {&quot;seven_r_label&quot;, type text}, {&quot;modernization_position&quot;, type text}, {&quot;coverage_score&quot;, Int64.Type}, {&quot;confidence&quot;, type text}, {&quot;portability_score&quot;, Int64.Type}, {&quot;landing_zone&quot;, type text}})</span></span>
<span class="line"><span>in</span></span>
<span class="line"><span>    #&quot;Geänderter Typ&quot;</span></span></code></pre></div><h3 id="after-paste-this-in-full" tabindex="-1">After (paste this in full) <a class="header-anchor" href="#after-paste-this-in-full" aria-label="Permalink to &quot;After (paste this in full)&quot;">​</a></h3><div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let</span></span>
<span class="line"><span>    Quelle = Csv.Document(File.Contents(SWAOExportPath &amp; &quot;\\dim_app.csv&quot;),[Delimiter=&quot;,&quot;, Columns=11, Encoding=65001, QuoteStyle=QuoteStyle.None]),</span></span>
<span class="line"><span>    #&quot;Höher gestufte Header&quot; = Table.PromoteHeaders(Quelle, [PromoteAllScalars=true]),</span></span>
<span class="line"><span>    #&quot;Geänderter Typ&quot; = Table.TransformColumnTypes(#&quot;Höher gestufte Header&quot;,{{&quot;app_id&quot;, type text}, {&quot;name&quot;, type text}, {&quot;business_domain&quot;, type text}, {&quot;business_criticality&quot;, type text}, {&quot;regulatory_class&quot;, type text}, {&quot;seven_r_label&quot;, type text}, {&quot;modernization_position&quot;, type text}, {&quot;coverage_score&quot;, Int64.Type}, {&quot;confidence&quot;, type text}, {&quot;portability_score&quot;, Int64.Type}, {&quot;landing_zone&quot;, type text}})</span></span>
<span class="line"><span>in</span></span>
<span class="line"><span>    #&quot;Geänderter Typ&quot;</span></span></code></pre></div><p><strong>The only change is on the Quelle line:</strong> the quoted absolute path becomes <code>SWAOExportPath &amp; &quot;\\dim_app.csv&quot;</code>. Everything else is identical.</p><hr><h2 id="quick-lookup-file-argument-for-each-of-the-17-single-app-queries" tabindex="-1">Quick lookup -- file argument for each of the 17 single-app queries <a class="header-anchor" href="#quick-lookup-file-argument-for-each-of-the-17-single-app-queries" aria-label="Permalink to &quot;Quick lookup -- file argument for each of the 17 single-app queries&quot;">​</a></h2><p>For each query, only the <strong>filename</strong> changes in the <code>File.Contents</code> call. Open Erweiterter Editor on the named query and replace the quoted absolute path with the right line below.</p><table tabindex="0"><thead><tr><th>Query name</th><th>Replacement Quelle line argument</th></tr></thead><tbody><tr><td><code>dim_app</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\dim_app.csv&quot;)</code></td></tr><tr><td><code>dim_control</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\dim_control.csv&quot;)</code></td></tr><tr><td><code>dim_evidence</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\dim_evidence.csv&quot;)</code></td></tr><tr><td><code>dim_pass</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\dim_pass.csv&quot;)</code></td></tr><tr><td><code>dim_regime</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\dim_regime.csv&quot;)</code></td></tr><tr><td><code>dim_severity</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\dim_severity.csv&quot;)</code></td></tr><tr><td><code>dim_wave</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\dim_wave.csv&quot;)</code></td></tr><tr><td><code>fact_assessments</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\fact_assessments.csv&quot;)</code></td></tr><tr><td><code>fact_controls</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\fact_controls.csv&quot;)</code></td></tr><tr><td><code>fact_findings</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\fact_findings.csv&quot;)</code></td></tr><tr><td><code>fact_pass_runs</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\fact_pass_runs.csv&quot;)</code></td></tr><tr><td><code>fact_risks</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\fact_risks.csv&quot;)</code></td></tr><tr><td><code>fact_runs</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\fact_runs.csv&quot;)</code></td></tr><tr><td><code>fact_signals</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\fact_signals.csv&quot;)</code></td></tr><tr><td><code>link_control_evidence</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\link_control_evidence.csv&quot;)</code></td></tr><tr><td><code>link_control_signal</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\link_control_signal.csv&quot;)</code></td></tr><tr><td><code>link_signal_evidence</code></td><td><code>File.Contents(SWAOExportPath &amp; &quot;\\link_signal_evidence.csv&quot;)</code></td></tr></tbody></table><p>So for example, in the <code>fact_signals</code> query the Erweiterter Editor opens to:</p><div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let</span></span>
<span class="line"><span>    Quelle = Csv.Document(File.Contents(&quot;C:\\...\\fact_signals.csv&quot;),[Delimiter=&quot;,&quot;, Columns=17, Encoding=65001, QuoteStyle=QuoteStyle.None]),</span></span>
<span class="line"><span>    ...</span></span></code></pre></div><p>You replace the <code>File.Contents(&quot;C:\\...\\fact_signals.csv&quot;)</code> part with <code>File.Contents(SWAOExportPath &amp; &quot;\\fact_signals.csv&quot;)</code>. Everything after the comma in the <code>Csv.Document(...)</code> call stays as-is (the <code>Columns=17, Encoding=...</code> settings are query-specific and correct).</p><hr><h2 id="portfolio-queries-19-queries-parameter-is-swaoportfolioexportpath" tabindex="-1">Portfolio queries -- 19 queries, parameter is <code>SWAOPortfolioExportPath</code> <a class="header-anchor" href="#portfolio-queries-19-queries-parameter-is-swaoportfolioexportpath" aria-label="Permalink to &quot;Portfolio queries -- 19 queries, parameter is \`SWAOPortfolioExportPath\`&quot;">​</a></h2><p>For the portfolio .pbit, the parameter name is different. The 19 queries are the 17 above PLUS:</p><table tabindex="0"><thead><tr><th>Query name</th><th>Replacement Quelle line argument</th></tr></thead><tbody><tr><td><code>fact_app_heatmap</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_app_heatmap.csv&quot;)</code></td></tr><tr><td><code>fact_app_summary</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_app_summary.csv&quot;)</code></td></tr></tbody></table><p>And the other 17 queries in the portfolio template use <strong><code>SWAOPortfolioExportPath</code></strong> (not <code>SWAOExportPath</code>) in the same pattern. So in the portfolio template:</p><table tabindex="0"><thead><tr><th>Query name</th><th>Replacement Quelle line argument</th></tr></thead><tbody><tr><td><code>dim_app</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\dim_app.csv&quot;)</code></td></tr><tr><td><code>dim_control</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\dim_control.csv&quot;)</code></td></tr><tr><td><code>dim_evidence</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\dim_evidence.csv&quot;)</code></td></tr><tr><td><code>dim_pass</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\dim_pass.csv&quot;)</code></td></tr><tr><td><code>dim_regime</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\dim_regime.csv&quot;)</code></td></tr><tr><td><code>dim_severity</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\dim_severity.csv&quot;)</code></td></tr><tr><td><code>dim_wave</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\dim_wave.csv&quot;)</code></td></tr><tr><td><code>fact_assessments</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_assessments.csv&quot;)</code></td></tr><tr><td><code>fact_controls</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_controls.csv&quot;)</code></td></tr><tr><td><code>fact_findings</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_findings.csv&quot;)</code></td></tr><tr><td><code>fact_pass_runs</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_pass_runs.csv&quot;)</code></td></tr><tr><td><code>fact_risks</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_risks.csv&quot;)</code></td></tr><tr><td><code>fact_runs</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_runs.csv&quot;)</code></td></tr><tr><td><code>fact_signals</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_signals.csv&quot;)</code></td></tr><tr><td><code>link_control_evidence</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\link_control_evidence.csv&quot;)</code></td></tr><tr><td><code>link_control_signal</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\link_control_signal.csv&quot;)</code></td></tr><tr><td><code>link_signal_evidence</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\link_signal_evidence.csv&quot;)</code></td></tr><tr><td><code>fact_app_heatmap</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_app_heatmap.csv&quot;)</code></td></tr><tr><td><code>fact_app_summary</code></td><td><code>File.Contents(SWAOPortfolioExportPath &amp; &quot;\\fact_app_summary.csv&quot;)</code></td></tr></tbody></table><hr><h2 id="after-all-17-or-19-queries-are-rewired" tabindex="-1">After all 17 (or 19) queries are rewired <a class="header-anchor" href="#after-all-17-or-19-queries-are-rewired" aria-label="Permalink to &quot;After all 17 (or 19) queries are rewired&quot;">​</a></h2><ol><li><strong>Start &gt; Schließen und übernehmen.</strong> All queries reload from whatever the parameter currently points at.</li><li>Verify a card on the report (Latest Assessment is good) shows the new bundle&#39;s data (e.g. <code>11.05.2026 06:02</code> after pointing at the real-LLM bundle).</li><li><strong>Datei &gt; Exportieren &gt; Power BI-Vorlage.</strong> Overwrite the existing .pbit at <code>C:\\Projects\\accenture\\swao\\docs\\templates\\powerbi\\swao-report.pbit</code> (or <code>swao-portfolio.pbit</code>). The fix is now permanent in the template.</li><li>Smoke-test: open the saved .pbit in a <strong>fresh</strong> PowerBI Desktop session. PowerBI should prompt for the parameter value. Paste a different bundle path and confirm all visuals re-render.</li></ol><p>After this, future bundle changes are one paste in <code>Parameter verwalten</code> -- no per-query edits ever again.</p><hr><h2 id="optional-polish-do-it-now-or-skip" tabindex="-1">Optional polish (do it now or skip) <a class="header-anchor" href="#optional-polish-do-it-now-or-skip" aria-label="Permalink to &quot;Optional polish (do it now or skip)&quot;">​</a></h2><p>While each query is open in Erweiterter Editor, you can also fix the <strong>integer-truncation legacy</strong> by changing <code>Int64.Type</code> to <code>type number</code> for columns that hold decimal values. This is purely optional; the dashboards already work because the visual format masks the truncation.</p><table tabindex="0"><thead><tr><th>Query</th><th>Columns to flip to <code>type number</code></th></tr></thead><tbody><tr><td><code>dim_app</code></td><td><code>coverage_score</code>, <code>portability_score</code></td></tr><tr><td><code>dim_evidence</code></td><td><code>reliability_weight</code></td></tr><tr><td><code>fact_assessments</code></td><td><code>score</code>, <code>threshold</code></td></tr><tr><td><code>fact_runs</code></td><td><code>duration_minutes</code>, <code>llm_total_cost_usd</code>, <code>lz_weight_sovereign_score</code>, <code>lz_weight_service_coverage</code>, <code>lz_weight_portability</code>, <code>lz_weight_cost_tier</code></td></tr></tbody></table><p>If you flip these, the Coverage % card on Page 1 may need its visual format set to &quot;Percent&quot; so 0.93 displays as 93% rather than 0,93. Other visuals likely handle the change automatically.</p><p>If you don&#39;t flip them, leave as-is and the current display behaviour stays. Either path ships a working dashboard.</p><hr><h2 id="summary-minimal-effort-path" tabindex="-1">Summary -- minimal effort path <a class="header-anchor" href="#summary-minimal-effort-path" aria-label="Permalink to &quot;Summary -- minimal effort path&quot;">​</a></h2><ol><li>Open swao-report.pbit (or your live .pbix).</li><li>Daten transformieren.</li><li>For each of the 17 queries: Erweiterter Editor, replace the <code>Csv.Document(File.Contents(&quot;C:\\\\...&quot;))</code> argument with <code>File.Contents(SWAOExportPath &amp; &quot;\\&lt;filename&gt;.csv&quot;)</code>. Fertig.</li><li>Schließen und übernehmen.</li><li>Datei &gt; Exportieren &gt; Power BI-Vorlage &gt; overwrite swao-report.pbit.</li><li>Repeat for swao-portfolio.pbit with the 19 queries and <code>SWAOPortfolioExportPath</code> parameter name.</li></ol><p>End state: changing the parameter once updates the whole dashboard. The .pbit ships with this baked in for future operators.</p>`,48)])])}const m=e(d,[["render",s]]);export{h as __pageData,m as default};
